#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);vector<int>h(n+1);for(int i=1;i<=n;i++)scanf("%d",&h[i]);stack<int>st;string out;for(int i=1;i<=n;i++){while(!st.empty()&&h[st.top()]<h[i])st.pop();out+=to_string(st.empty()?0:st.top());out+=' ';st.push(i);}out.pop_back();printf("%s\n",out.c_str());}
